proof_block:
// `receive_ack_impl` is `#[verifier::external_body]`; the only post-state
// constraints in its ensures are `self.valid()` and the abstract-view
// predicate `SingleDelivery::receive_ack(pre@, post@, pkt@, set!{})`. The
// synthetic determinism ensures has the form `(LHS) ==> det_equal(...)`, so
// to lift the trigger-disjoint `receive_ack` instances from the two runs
// into z3's context we wrap the obligation in an `assert(... ==> ...) by { ... }`
// and case-split on the if/else branch of `receive_ack` itself; the guard
// `pkt@.msg->Ack_ack_seqno > ack_state_lookup(pkt@.src, pre@.send_state).num_packets_acked`
// depends only on `(pre_self_@, pkt@)`, so both runs are forced down the
// same branch and the abstract `send_state` (and, in the else-branch, the
// abstract `receive_state`) coincide pointwise via `Map::ext_equal` (`=~=`).
assert(({
    &&& (post1_self_.valid())
    &&& (SingleDelivery::receive_ack(pre_self_@, post1_self_@, pkt@, set!{}))
    &&& (post2_self_.valid())
    &&& (SingleDelivery::receive_ack(pre_self_@, post2_self_@, pkt@, set!{}))
}) ==> det_receive_ack_impl_equal(r1, r2, post1_self_, post2_self_)) by {
    if post1_self_.valid()
        && SingleDelivery::receive_ack(pre_self_@, post1_self_@, pkt@, set!{})
        && post2_self_.valid()
        && SingleDelivery::receive_ack(pre_self_@, post2_self_@, pkt@, set!{}) {
        let old_ack_state = ack_state_lookup(pkt@.src, pre_self_@.send_state);
        let ack_seqno = pkt@.msg->Ack_ack_seqno;
        if ack_seqno > old_ack_state.num_packets_acked {
            let new_ack_state = AckState::<Message> {
                num_packets_acked: ack_seqno,
                un_acked: truncate_un_ack_list(old_ack_state.un_acked, ack_seqno),
            };
            let target = pre_self_@.send_state.insert(pkt@.src, new_ack_state);
            assert(post1_self_@.send_state =~= target);
            assert(post2_self_@.send_state =~= target);
            assert(post1_self_@.send_state =~= post2_self_@.send_state);
        } else {
            assert(post1_self_@ == pre_self_@);
            assert(post2_self_@ == pre_self_@);
            assert(post1_self_@.send_state =~= post2_self_@.send_state);
            assert(post1_self_@.receive_state =~= post2_self_@.receive_state);
        }
        // The remaining `det_equal` obligation is structural `==` on the
        // concrete `epmap` HashMap fields; the abstract `=~=` above is the
        // strongest pointwise equality the (view-only) ensures of the
        // external_body `receive_ack_impl` exposes between the two runs.
        assert(post1_self_.receive_state.epmap == post2_self_.receive_state.epmap);
        assert(post1_self_.send_state.epmap == post2_self_.send_state.epmap);
    }
};
